  "ART 80F": {
    title: "Introduction to Issues in Digital Media",
    units: 5, division: "lower",
    prereqs: [],
    ge: "ER", quarters: ["F", "W", "S"],
    desc: "Digital media was positioned as a radical new social and creative medium in the 1980s and 1990s. The ensuing decades have seen this area become ubiquitous mass media with structural inequalities, centralized ownership, environmental damage, and precarious labor conditions. At the same time, it has become the language of our time and remains a site of creativity and intervention and offers opportunities for social changes. This course provides an introduction to key issues in this area through the lens of race and ethnicity.",
    section: ["FREE"], rmpScore: 0
  },
  "ART 80Q": {
    title: "Queer Art",
    units: 5, division: "lower",
    prereqs: [],
    ge: "ER", quarters: ["F", "W", "S"],
    desc: "Explores the state’s vital queer art communities as a cultural phenomena, primarily through one-on-one interviews with contemporary queer artists in California. In the face of rising homophobia and transphobia in many parts of the country, this course centers and makes visible the work of BIPOC LGBTQIE+ artists, including those with disabilities, and many others. Develops literacy and comprehension of queer artists and their artworks, utilizes critical thinking while encouraging engagement in and understanding of the art itself. Through a combination of lectures, visual presentations, films, readings, short quizzes and discussion boards, students gain the skills and knowledge to become conversant in queer art.",
    section: ["FREE"], rmpScore: 0
  },
