    units: 5, division: "upper",
    prereqs: [["PHIL 9"], ["PHIL 11", "PHIL 22", "PHIL 23", "PHIL 24", "PHIL 80E", "BME 80G", "PHIL 80G", "PHIL 80M", "PHIL 80S"], ["PHIL 100A", "PHIL 100B", "PHIL 100C"]],
