    prereqs: [["PSYC 100"]],
    ge: null, quarters: ["F", "W", "S"],
    desc: "Topics include: what makes a successful intervention; what happens before the formal intervention begins; the ethics involved with interventions; different methods for assessing interventions; and different praxis models. Satisfies the seminar requirement. Satisfies the senior comprehensive requirement. A service component is involved.",
    section: ["FREE"], rmpScore: 0
