  "CMPM 176": {
    title: "Game Systems",
    units: 5, division: "upper",
    prereqs: [["CMPM 80K"]],
    ge: null, quarters: ["F", "W", "S"],
    desc: "Presents game design as the interplay of multiple interacting game systems. Surveys various game systems: movement, combat, reward, economic, logistics, quest, information visibility, narrative. Students explore systems via study, design, and play of board, card, and computer games.",
    section: ["FREE"], rmpScore: 0
  },
  "CMPM 177": {
    title: "Creative Strategies for Designing Interactive Media",
    units: 5, division: "upper",
    prereqs: [],
    ge: null, quarters: ["F", "W", "S"],
    desc: "Surveys tactical, structural, contextual, and other methods to enhance creativity and innovation in the design of games and other interactive media. Investigates strategies for creativity and innovation drawn from diverse fields, including interactive affordances, narrative and poetics, biology, contextual inquiry, and design research. To innovate in a field of fixed genres is challenging: the allure of modeling exemplars is strong. Although imitation can be successful in the marketplace, the most creative action occurs on the leading edge of change. Innovation benefits from strategies and methods that are directly aimed at exploring new perspectives and structures to learn through the process of discovery.",
    section: ["FREE"], rmpScore: 0
  },
  "CMPM 178": {
    title: "Human-Centered Design Research",
    units: 5, division: "upper",
    prereqs: [],
    ge: "PR-C", quarters: ["F", "W", "S"],
    desc: "Students move through a rigorous design-research process involving skills and principles in human-centered design research as well as selected formal research methods. They learn to use tools for ideation, human-centered qualitative research, domestic probes, mock-ups, and prototypes.",
    section: ["FREE"], rmpScore: 0
  },
  "CMPM 179": {
    title: "Game Design Practicum",
    units: 5, division: "upper",
    prereqs: [["CMPM 120"], ["CMPM 80K"]],
    ge: "PR-C", quarters: ["F", "W", "S"],
    desc: "Provides the opportunity to practice the creation of novel computer games. Students learn a new game-making technology, then create three games using this technology.",
    section: ["FREE"], rmpScore: 0
  },
  "CMPM 180": {
    title: "Topics in Computational Media",
    units: 5, division: "upper",
    prereqs: [],
    ge: null, quarters: ["F", "W", "S"],
    desc: "Allows students to explore topics in the computational media field and practice design in a wide variety of applications and areas, including but not limited to interactive computational experiences, AI and poetry, smart cities and game design, ethics and computational media, and computational media culture. Course presentation and assessment will vary by topic and instructor.",
    section: ["FREE"], rmpScore: 0
  },
  "CMPM 181": {
    title: "Games for Impact Studio I",
    units: 5, division: "upper",
    prereqs: [],
    ge: null, quarters: ["F", "W", "S"],
    desc: "Students work in teams to develop serious games. Course involves multiple aspects of game development, with an emphasis on identifying the topic and goal for the game, initiating research on the topic, and developing an initial concept design. The concept design phase will include several iterations and experimentation with various techniques and game elements toward addressing the goal established. The process also involves identifying assessment and efficacy measures given the goal identified. These measures are theory-based and will be developed based on the initial research conducted. The outcome should be a concept design and prototype. Taught in conjunction with CMPM 255 . Students cannot receive credit for this course and CMPM 255 .",
    section: ["FREE"], rmpScore: 0
  },
  "CMPM 182": {
    title: "Games for Impact Studio II",
    units: 5, division: "upper",
    prereqs: [["CMPM 181"]],
    ge: null, quarters: ["F", "W", "S"],
    desc: "Students work in teams to polish and assess their games. This is a continuation of the Games for Impact Studio series from Studio I. The course will involve aspects of (I) game production, with an emphasis on tuning the design and polishing it, and (II) assessment, where students develop their methods for assessment, which include usability testing, as well as goal assessment based on metrics development, data collection, and analysis. The outcomes are: the game is polished and tested, as well as a report on the evaluation of the game. Taught in conjunction with CMPM 256 . Students cannot receive credit for this course and CMPM 256 .",
    section: ["FREE"], rmpScore: 0
  },
