  "FMST 194C": {
    title: "Gender and Iconicity",
    units: 5, division: "upper",
    prereqs: [["FMST 1"], ["FMST 100"]],
    ge: null, quarters: ["F", "W", "S"],
    desc: "Examines icons and the processes through which an iconicity is constructed and circulated in its complexity. Icons and iconicities often link or articulate various ideologies, affects, and systems of thought into a potent symbol or a mythology. Icons constitute norms, but also disrupt them; icons could articulate new technologies, aesthetics and their representations of the self with purportedly older modes of being in the world, such as a transcendent belief in a god, a faith, etc.",
    section: ["FREE"], rmpScore: 0
  },
  "FMST 194D": {
    title: "Feminist Science Studies",
    units: 5, division: "upper",
    prereqs: [["FMST 1"], ["FMST 100"]],
    ge: null, quarters: ["F", "W", "S"],
    desc: "Examines different feminist approaches to understanding the nature of scientific practices. Particular attention paid to notions of evidence, methods, cultural and material constraints, and the heterogeneous nature of laboratory practices. Considers the ways in which gender, race, and sexuality are constructed by science and how they influence both scientific practices and conceptions of science. Also examines the feminist commitment to taking social factors into account without forfeiting the notion of objectivity.",
    section: ["FREE"], rmpScore: 0
  },
