    units: 5, division: "lower",
    prereqs: [],
    ge: "IM", quarters: ["F", "W", "S"],
    desc: "Introduces a selective survey of music in animated film (Disney, Pixar and DreamWorks), both instrumental and vocal, highlighting the representative works from the 1930s to the present. Through listening and viewing, students explore the use and role of music in animated film.",
    section: ["FREE"], rmpScore: 0
